@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="ToggleExpanded" style="cursor: pointer;">
        <h6 class="mb-0">Change Password</h6>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger py-2">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success py-2">@successMessage</div>
            }
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="HandleSubmit" disabled="@isSubmitting">
                @(isSubmitting ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isSubmitting;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task HandleSubmit()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            successMessage = "Password updated successfully.";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

