@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<h4 class="mb-4">Profile</h4>

@if (!string.IsNullOrEmpty(toastMessage))
{
    <div class="alert alert-success alert-dismissible fade show py-2" role="alert">
        @toastMessage
        <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
    </div>
}

<div class="row">
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="displayName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="bio"></textarea>
        </div>
    </div>
    <div class="col-md-4 text-center">
        <div class="mb-3">
            <label class="form-label d-block">Avatar Preview</label>
            <div class="border rounded p-2 d-inline-block mb-2" style="width: 150px; height: 150px; overflow: hidden;">
                <img src="@avatarUrl" alt="Avatar" class="img-fluid rounded"
                     style="width: 100%; height: 100%; object-fit: cover;"
                     @onerror="() => {}" />
            </div>
            <div class="small text-muted text-break">@avatarUrl</div>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-primary" @onclick="Save" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Changes")
    </button>
    <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@(!HasChanges)">
        Discard Changes
    </button>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool isSaving;
    private string? toastMessage;

    private bool HasChanges =>
        Profile is not null &&
        (displayName != Profile.DisplayName ||
         email != Profile.Email ||
         bio != Profile.Bio);

    protected override void OnParametersSet()
    {
        if (Profile is not null && !HasChanges)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        if (Profile is null) return;
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            toastMessage = "Profile saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        toastMessage = null;
    }
}

@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<h4 class="mb-4">Notifications</h4>

@if (!string.IsNullOrEmpty(toastMessage))
{
    <div class="alert alert-success alert-dismissible fade show py-2" role="alert">
        @toastMessage
        <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Notification Channels</h6>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" checked="@emailNotifications"
                   @onchange="e => emailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" checked="@pushNotifications"
                   @onchange="e => pushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" checked="@weeklyDigest"
                   @onchange="e => weeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Muted Channels</h6>
        @foreach (var channel in AllChannels)
        {
            var isMuted = mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    @channel <span class="text-muted small">@(isMuted ? "(muted)" : "")</span>
                </label>
            </div>
        }
    </div>
</div>

<button class="btn btn-primary" @onclick="Save" disabled="@isSaving">
    @(isSaving ? "Saving…" : "Save Preferences")
</button>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private bool isSaving;
    private string? toastMessage;

    private static readonly string[] AllChannels =
        ["general", "engineering", "marketing", "random", "announcements", "design"];

    protected override void OnParametersSet()
    {
        if (Prefs is null) return;
        emailNotifications = Prefs.EmailNotifications;
        pushNotifications = Prefs.PushNotifications;
        weeklyDigest = Prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(Prefs.MutedChannels);
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications, weeklyDigest,
                mutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            toastMessage = "Notification preferences saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<h4 class="mb-4">Security</h4>

<div class="mb-4">
    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@twoFactorEnabled"
                       @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <p class="text-muted small mt-2 mb-0">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
            </p>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Active Sessions</h6>
        @if (Settings?.Sessions is { Count: > 0 })
        {
            <div class="table-responsive">
                <table class="table table-sm table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Settings.Sessions)
                        {
                            var isCurrent = session == Settings.Sessions[0];
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
        else
        {
            <p class="text-muted mb-0">No active sessions found.</p>
        }
    </div>
</div>

<RevokeSessionDialog IsVisible="showRevokeDialog"
                     SessionDevice="@(sessionToRevoke?.Device ?? "")"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public SecuritySettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            twoFactorEnabled = Settings.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args) =>
        await OnChangePassword.InvokeAsync(args);

    private void ShowRevokeDialog(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(sessionToRevoke.Id);
        }
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

