@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<h4 class="mb-4">Security</h4>

<div class="mb-4">
    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@twoFactorEnabled"
                       @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Settings?.LastPasswordChange is not null)
        {
            <p class="text-muted small mt-2 mb-0">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
            </p>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h6 class="card-title mb-3">Active Sessions</h6>
        @if (Settings?.Sessions is { Count: > 0 })
        {
            <div class="table-responsive">
                <table class="table table-sm table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Settings.Sessions)
                        {
                            var isCurrent = session == Settings.Sessions[0];
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
        else
        {
            <p class="text-muted mb-0">No active sessions found.</p>
        }
    </div>
</div>

<RevokeSessionDialog IsVisible="showRevokeDialog"
                     SessionDevice="@(sessionToRevoke?.Device ?? "")"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public SecuritySettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            twoFactorEnabled = Settings.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePassword((string Current, string New) args) =>
        await OnChangePassword.InvokeAsync(args);

    private void ShowRevokeDialog(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(sessionToRevoke.Id);
        }
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings

<h4 class="mb-4">Appearance</h4>

@if (!string.IsNullOrEmpty(toastMessage))
{
    <div class="alert alert-success alert-dismissible fade show py-2" role="alert">
        @toastMessage
        <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
    </div>
}

<div class="row">
    <div class="col-md-7">
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Theme</h6>
                @foreach (var t in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                               value="@t" checked="@(theme == t)"
                               @onchange="() => theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Font Size</h6>
                @foreach (var s in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{s}")"
                               value="@s" checked="@(fontSize == s)"
                               @onchange="() => fontSize = s" />
                        <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Language</h6>
                <select class="form-select" @bind="language">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@compactMode"
                           @onchange="e => compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="Save" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save")
        </button>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Live Preview</h6>
            </div>
            <div class="card-body preview-area"
                 style="@GetPreviewStyle()">
                <h6 style="@GetPreviewFontStyle()">Dashboard</h6>
                <p style="@GetPreviewFontStyle()" class="@(compactMode ? "mb-1" : "mb-3")">
                    This is how your content will look with the selected settings.
                </p>
                <div class="d-flex gap-2 @(compactMode ? "mb-1" : "mb-3")">
                    <span class="badge bg-primary" style="@GetPreviewFontStyle()">Badge</span>
                    <span class="badge bg-success" style="@GetPreviewFontStyle()">Active</span>
                </div>
                <div class="@(compactMode ? "p-1" : "p-2") border rounded" style="@GetPreviewFontStyle()">
                    <small class="text-muted">Card preview element</small>
                    <div>Sample item row</div>
                    <div>Another item row</div>
                </div>
                <p class="text-muted small mt-2 mb-0">
                    Theme: @theme · Font: @fontSize · Compact: @(compactMode ? "On" : "Off")
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;
    private bool isSaving;
    private string? toastMessage;

    private static readonly string[] Languages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is null) return;
        theme = Settings.Theme;
        fontSize = Settings.FontSize;
        language = Settings.Language;
        compactMode = Settings.CompactMode;
    }

    private string GetPreviewStyle()
    {
        var bg = theme switch
        {
            "Dark" => "background-color: #1e1e1e; color: #d4d4d4;",
            "System" => "background-color: #f0f0f0; color: #333;",
            _ => "background-color: #ffffff; color: #212529;"
        };
        return $"{bg} transition: all 0.3s ease; min-height: 200px;";
    }

    private string GetPreviewFontStyle() => fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            toastMessage = "Appearance saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

