            <div class="card-body">
                <h6 class="card-title mb-3">Font Size</h6>
                @foreach (var s in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{s}")"
                               value="@s" checked="@(fontSize == s)"
                               @onchange="() => fontSize = s" />
                        <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Language</h6>
                <select class="form-select" @bind="language">
                    @foreach (var lang in Languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@compactMode"
                           @onchange="e => compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="Save" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save")
        </button>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Live Preview</h6>
            </div>
            <div class="card-body preview-area"
                 style="@GetPreviewStyle()">
                <h6 style="@GetPreviewFontStyle()">Dashboard</h6>
                <p style="@GetPreviewFontStyle()" class="@(compactMode ? "mb-1" : "mb-3")">
                    This is how your content will look with the selected settings.
                </p>
                <div class="d-flex gap-2 @(compactMode ? "mb-1" : "mb-3")">
                    <span class="badge bg-primary" style="@GetPreviewFontStyle()">Badge</span>
                    <span class="badge bg-success" style="@GetPreviewFontStyle()">Active</span>
                </div>
                <div class="@(compactMode ? "p-1" : "p-2") border rounded" style="@GetPreviewFontStyle()">
                    <small class="text-muted">Card preview element</small>
                    <div>Sample item row</div>
                    <div>Another item row</div>
                </div>
                <p class="text-muted small mt-2 mb-0">
                    Theme: @theme · Font: @fontSize · Compact: @(compactMode ? "On" : "Off")
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;
    private bool isSaving;
    private string? toastMessage;

    private static readonly string[] Languages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is null) return;
        theme = Settings.Theme;
        fontSize = Settings.FontSize;
        language = Settings.Language;
        compactMode = Settings.CompactMode;
    }

    private string GetPreviewStyle()
    {
        var bg = theme switch
        {
            "Dark" => "background-color: #1e1e1e; color: #d4d4d4;",
            "System" => "background-color: #f0f0f0; color: #333;",
            _ => "background-color: #ffffff; color: #212529;"
        };
        return $"{bg} transition: all 0.3s ease; min-height: 200px;";
    }

    private string GetPreviewFontStyle() => fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            toastMessage = "Appearance saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}
