<h4 class="mb-4">Profile</h4>

@if (!string.IsNullOrEmpty(toastMessage))
{
    <div class="alert alert-success alert-dismissible fade show py-2" role="alert">
        @toastMessage
        <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
    </div>
}

<div class="row">
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="displayName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="bio"></textarea>
        </div>
    </div>
    <div class="col-md-4 text-center">
        <div class="mb-3">
            <label class="form-label d-block">Avatar Preview</label>
            <div class="border rounded p-2 d-inline-block mb-2" style="width: 150px; height: 150px; overflow: hidden;">
                <img src="@avatarUrl" alt="Avatar" class="img-fluid rounded"
                     style="width: 100%; height: 100%; object-fit: cover;"
                     @onerror="() => {}" />
            </div>
            <div class="small text-muted text-break">@avatarUrl</div>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-primary" @onclick="Save" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Changes")
    </button>
    <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@(!HasChanges)">
        Discard Changes
    </button>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool isSaving;
    private string? toastMessage;

    private bool HasChanges =>
        Profile is not null &&
        (displayName != Profile.DisplayName ||
         email != Profile.Email ||
         bio != Profile.Bio);

    protected override void OnParametersSet()
    {
        if (Profile is not null && !HasChanges)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        if (Profile is null) return;
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            toastMessage = "Profile saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        toastMessage = null;
    }
}

