@page "/settings"
@using sv_5ba01906ffcc4ef982fa258272d7d044.Services
@using sv_5ba01906ffcc4ef982fa258272d7d044.Models
@namespace sv_5ba01906ffcc4ef982fa258272d7d044.Components.Pages.Settings
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <aside class="settings-nav">
        <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="ChangeSection" />
    </aside>
    <section class="settings-content">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @switch (activeSection)
            {
                case "profile":
                    <ProfileSection Profile="@profile" OnSave="SaveProfile" />
                    break;
                case "notifications":
                    <NotificationsSection Prefs="@notificationPrefs" OnSave="SaveNotifications" />
                    break;
                case "security":
                    <SecuritySection Settings="@securitySettings"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "appearance":
                    <AppearanceSection Settings="@appearanceSettings" OnSave="SaveAppearance" />
                    break;
            }
        }
